    def __init__(self, maxSize):
        self.cap = maxSize
        self.data = []

    def push(self, x):
        if len(self.data) < self.cap:
            self.data.append(x)

    def pop(self):
        if not self.data:
            return -1
        return self.data.pop()

    def increment(self, k, val):
        for i in range(min(k, len(self.data))):
            self.data[i] += val

