class CustomStack:
    def __init__(self, maxSize):
        self.cap = maxSize
        self.stack = []

    def push(self, x):
        if len(self.stack) < self.cap:
            self.stack.append(x)

    def pop(self):
        if not self.stack:
            return -1
        return self.stack.pop()

    def increment(self, k, val):
        bound = min(k, len(self.stack))
        for i in range(bound):
            self.stack[i] += val

