class CustomStack {
    constructor(maxSize) {
        this.cap = maxSize;
        this.stack = [];
    }
    push(x) {
        if (this.stack.length < this.cap) {
            this.stack.push(x);
        }
    }
    pop() {
        if (this.stack.length === 0) return -1;
        return this.stack.pop();
    }
    increment(k, val) {
        const bound = Math.min(k, this.stack.length);
        for (let i = 0; i < bound; i++) {
            this.stack[i] += val;
        }
    }
}
